export function getRandomIdiom(): Idiom {
  const randomIndex = Math.floor(Math.random() * IDIOMS.length);
  return IDIOMS[randomIndex];
}

export function findIdiomByWord(word: string): Idiom | undefined {
  return IDIOMS.find(idiom => idiom.word === word);
}
